package com.restaurant.order.service.impl;

import com.restaurant.order.client.MenuClient;
import com.restaurant.order.client.PaymentServiceClient;
import com.restaurant.order.dto.request.OrderItemRequest;
import com.restaurant.order.dto.request.PlaceOrderRequest;
import com.restaurant.order.dto.response.OrderResponse;
import com.restaurant.order.dto.snapshot.MealPriceSnapshot;
import com.restaurant.order.entity.Order;
import com.restaurant.order.entity.OrderItem;
import com.restaurant.order.enums.OrderStatus;
import com.restaurant.order.enums.PaymentMethod;
import com.restaurant.order.events.OrderCreatedEvent;
import com.restaurant.order.events.payments.PaymentRefundRequestedEvent;
import com.restaurant.order.events.points.PointRedemptionRollbackRequestedEvent;
import com.restaurant.order.events.points.PointRedemptionRequestedEvent;
import com.restaurant.order.events.points.RewardPointsEarnedEvent;
import com.restaurant.order.exception.MenuServiceException;
import com.restaurant.order.exception.OrderNotFoundException;
import com.restaurant.order.exception.PointsException;
import com.restaurant.order.mapper.OrderMapper;
import com.restaurant.order.messaging.MessagePublisher;
import com.restaurant.order.repository.OrderRepository;
import com.restaurant.order.service.OrderCalculator;
import com.restaurant.order.service.OrderService;
import jakarta.annotation.Nullable;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.transaction.interceptor.TransactionAspectSupport;
import org.springframework.web.server.ResponseStatusException;

import java.util.List;
import java.util.UUID;

@Service
@Slf4j
@RequiredArgsConstructor
public class OrderServiceImpl implements OrderService {

    private final OrderRepository orderRepository;
    private final MessagePublisher messagePublisher;
    private final OrderMapper orderMapper;
    private final OrderCalculator orderCalculator;
    private final MenuClient menuClient;
    private final PaymentServiceClient paymentServiceClient;

    @Transactional(rollbackFor = Exception.class)
    @Override
    public OrderResponse placeOrder(PlaceOrderRequest request, Long clientId) {
        log.info("Placing order for customerId: {}", clientId);

        // 1. Validate points
        int pointsToRedeem = request.points() != null ? request.points() : 0;
        int discount = switch (pointsToRedeem) {
            case 0 -> 0;
            case 100 -> 10;
            case 200 -> 20;
            case 300 -> 30;
            default -> throw new PointsException(
                    "Invalid redemption points. Allowed values are 100, 200, or 300." // cancel order process
            );
        };

        Order order = Order.builder()
                .clientId(clientId)
                .discount(discount)
                .paymentMethod(request.paymentMethod())
                .build();

        // 2. Fetch price snapshots from menu-service and build items
        for (OrderItemRequest itemReq : request.items()) {
            MealPriceSnapshot meal = menuClient.getMealById(itemReq.mealId());
            order.getItems().add(OrderItem.builder()
                    .order(order)
                    .mealId(meal.id())
                    .snapshotName(meal.name())
                    .snapshotPrice(meal.price())
                    .quantity(itemReq.quantity())
                    .build());
        }

        // 3. Calculate total price (with point discount if applicable)
        orderCalculator.calculateTotals(order);

        // 4. Reserve stock — if this fails, nothing is written to DB
        log.info("Reserving stock for order...");
        try {
            menuClient.reserveStock(request.items());
        } catch (Exception e) {
            log.error("Failed to reserve stock for order.", e);
            throw new MenuServiceException("Cannot reserve stock for order. The stock may be insufficient");
        }

        try {
            // 5. Persist to DB — status starts as PENDING
            Order savedOrder = orderRepository.save(order);
            log.info("Order saved with id: {} and status PENDING", savedOrder.getId());

            // 6. Trigger next step in saga
            if (pointsToRedeem != 0) {
                log.info("Triggering async point redemption for {} points...", pointsToRedeem);
                publishPointRedemptionRequestedEvent(savedOrder);
            } else {
                // Check payment method - only call payment service for non-cash payments
                if (!request.paymentMethod().equals(PaymentMethod.CASH)) {
                    savedOrder.setStatus(OrderStatus.AWAITING_PAYMENT);
                    createPaymentIntentSync(savedOrder);
                } else {
                    log.info("Payment method is CASH for order {}, skipping payment service call", savedOrder.getId());
                    publishOrderCreatedEvent(savedOrder);
                }
                orderRepository.save(savedOrder);
            }

            return orderMapper.toResponse(savedOrder);
        } catch (Exception e) {
            log.error("Failed to complete order placement for clientId: {}. Rolling back stock.", clientId, e);
            try {
                menuClient.rollbackStock(buildItemRequests(order));
            } catch (Exception rollbackEx) {
                log.error("CRITICAL: Failed to rollback stock after order placement failure for clientId: {}", clientId, rollbackEx);
            }
            throw e; // Re-throw the original exception (PointsException, PaymentException, or DB exception)
        }
    }

    @Transactional
    @Override
    public void confirmOrder(Long orderId, Long ticketId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.CONFIRMED) {
                            log.info("Order {} already confirmed, skipping.", orderId);
                            return;
                        }
                        order.setStatus(OrderStatus.CONFIRMED);
                        orderRepository.save(order);
                        log.info("Order {} status updated to CONFIRMED (ticket {})", orderId, ticketId);

                        // Reward points: 1 point per 5 EGP spent
                        if (order.getDiscount() == 0) {
                            int pointsToReward = order.getTotalPrice().intValue() / 5;
                            if (pointsToReward > 0) {
                                messagePublisher.publishRewardPointsEarned(
                                        new RewardPointsEarnedEvent(order.getClientId(), pointsToReward, order.getId())
                                );
                            }
                        }
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to confirm order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for confirmation, orderId: {}", orderId)
        );
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public void markPaymentSucceeded(Long orderId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.PAID) {
                            log.info("Order {} already marked as PAID, skipping.", orderId);
                            return;
                        }

                        if (order.getStatus() != OrderStatus.AWAITING_PAYMENT) {
                            log.warn("Order {} is in status {}, expected AWAITING_PAYMENT. Ignoring payment success.", orderId, order.getStatus());
                            return;
                        }

                        order.setStatus(OrderStatus.PAID);
                        orderRepository.save(order);
                        log.info("Payment succeeded for order {}. Notifying kitchen...", orderId);
                        publishOrderCreatedEvent(order);
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to process payment success for order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for payment success, ID: {}", orderId)
        );
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public void markPaymentFailed(Long orderId, String reason) {
        log.info("Payment failed for order {}, reason: {}. Cancelling order...", orderId, reason);
        cancelOrder(orderId, "Payment failed: " + reason);
    }


    @Transactional
    @Override
    public void markPointRedemptionSucceeded(Long orderId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.AWAITING_PAYMENT || order.getStatus() == OrderStatus.PAID) {
                            log.info("Order {} already processed point redemption, skipping.", orderId);
                            return;
                        }

                        if (order.getStatus() != OrderStatus.PENDING) {
                            log.warn("Order {} is in status {}, expected PENDING. Ignoring point redemption success.", orderId, order.getStatus());
                            return;
                        }

                        // Check payment method - only call payment service for non-cash payments
                        if (!order.getPaymentMethod().equals(PaymentMethod.CASH)) {
                            order.setStatus(OrderStatus.AWAITING_PAYMENT);
                            orderRepository.save(order);
                            log.info("Point redemption succeeded for order {}. Proceeding to payment...", orderId);
                            createPaymentIntentSync(order);
                        } else {
                            log.info("Payment method is CASH for order {}, skipping payment service call and publishing order created", orderId);
                            publishOrderCreatedEvent(order);
                        }
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to process point redemption success for order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for point redemption success, ID: {}", orderId)
        );
    }

    @Transactional
    @Override
    public void markPointRedemptionFailed(Long orderId, String reason) {
        log.info("Point redemption failed for order {}, reason: {}. Cancelling order...", orderId, reason);
        cancelOrder(orderId, "Point redemption failed: " + reason);
    }

    @Override
    public OrderResponse retrieveOrder(Long orderId) {
        Order order = orderRepository.findById(orderId)
                .orElseThrow(() -> new OrderNotFoundException(orderId));
        return orderMapper.toResponse(order);
    }

    @Transactional
    @Override
    public void cancelOrder(Long orderId, @Nullable String reason) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        OrderStatus status = order.getStatus();

                        // 0. Short-circuit if already canceled
                        if (status == OrderStatus.CANCELED) {
                            log.info("Order {} already cancelled, skipping.", orderId);
                            return;
                        }

                        // 1. Refuse Cancellation Check
                        boolean isAdvancedStage = (status == OrderStatus.PREPARING || status == OrderStatus.READY);
                        boolean isPaidOrConfirmed = (status == OrderStatus.PAID || status == OrderStatus.CONFIRMED);
                        boolean isNotCash = !PaymentMethod.CASH.equals(order.getPaymentMethod());

                        if (isAdvancedStage) {
                            log.warn("Cancellation refused for order {}. Status is {} ", orderId, status);
                            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Cannot cancel order that is already started preparing");
                        }

                        // 2. Rollback Stock
                        try {
                            log.info("Rolling back stock for cancelled order {}", orderId);
                            menuClient.rollbackStock(buildItemRequests(order));
                        } catch (Exception e) {
                            log.error("Failed to rollback stock for cancelled order {}", orderId, e);
                        }

                        // 3. Refund Payment if order was paid or confirmed (but passes cancellation check)
                        if (isPaidOrConfirmed && isNotCash) {
                            log.info("Triggering payment refund for order {}", orderId);
                            publishPaymentRefundEvent(order);
                        }

                        // 4. Rollback Points (Refund points if discount exists and order is NOT pending)
                        if (order.getDiscount() != 0 && status != OrderStatus.PENDING) {
                            log.info("Triggering point redemption rollback for order {}", orderId);
                            publishPointRedemptionRollbackEvent(order);
                        }

                        // 5. Finalize Cancellation State
                        order.setStatus(OrderStatus.CANCELED);
                        orderRepository.save(order);
                        log.info("Order {} cancelled. Reason: {}", orderId, reason != null ? reason : "Client Cancellation Request");

                    } catch (ResponseStatusException e) {
                        // Pass through client errors cleanly without marking transaction for forced system rollback
                        throw e;
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to cancel order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> {
                    log.error("MANUAL INTERVENTION REQUIRED: Order not found for cancellation, orderId: {}", orderId);
                    throw new ResponseStatusException(HttpStatus.NOT_FOUND, "Order not found");
                }
        );
    }

    @Transactional
    @Override
    public void onTicketReady(Long orderId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.READY) {
                            log.info("Order {} already marked as READY, skipping.", orderId);
                            return;
                        }
                        order.setStatus(OrderStatus.READY);
                        orderRepository.save(order);
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to mark order {} as ready. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for ticket ready status, ID: {}", orderId)
        );
    }

    @Transactional
    @Override
    public void onTicketStarted(Long orderId, Long ticketId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.PREPARING) {
                            log.info("Order {} already marked as PREPARING, skipping.", orderId);
                            return;
                        }
                        order.setStatus(OrderStatus.PREPARING);
                        orderRepository.save(order);
                        log.info("Order {} status updated to PREPARING (ticket {})", orderId, ticketId);
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to mark order {} as preparing. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for ticket started status, ID: {}", orderId)
        );
    }


    // --- Private helpers ---

    private List<OrderItemRequest> buildItemRequests(Order order) {
        return order.getItems().stream()
                .map(item -> new OrderItemRequest(item.getMealId(), item.getQuantity()))
                .toList();
    }

    private void publishOrderCreatedEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishOrderCreated(
                    new OrderCreatedEvent(order.getId()), sagaId, correlationId);
        } catch (Exception e) {
            log.error("Failed to publish order.created event for orderId: {}", order.getId(), e);
            throw new RuntimeException("Order created but failed to notify kitchen service", e);
        }
    }

    private void createPaymentIntentSync(Order order) {
        PaymentServiceClient.PaymentIntentResponse response = paymentServiceClient.createPaymentIntent(

                order.getId(), order.getClientId(), order.getTotalPrice(), "egp");

        order.setStripePaymentIntentId(response.paymentIntentId());
        order.setStripeClientSecret(response.clientSecret());
        orderRepository.save(order);
        log.info("PaymentIntent created and stored for order {}: intentId={}", order.getId(), response.paymentIntentId());
    }

    private void publishPointRedemptionRequestedEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishPointRedemptionRequested(
                    new PointRedemptionRequestedEvent(order.getId(), order.getClientId(), order.getDiscount() * 10), sagaId, correlationId);
        } catch (Exception e) {
            log.error("Failed to publish point-redemption.requested event for orderId: {}", order.getId(), e);
            throw new PointsException("Order placement failed due to point redemption request failure");
        }
    }

    private void publishPointRedemptionRollbackEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishPointRedemptionRollback(
                    new PointRedemptionRollbackRequestedEvent(order.getId(), order.getClientId(), order.getDiscount() * 10), sagaId, correlationId);
        } catch (Exception e) {
            log.error("CRITICAL: Failed to publish point-redemption.rollback event for orderId: {}", order.getId(), e);
        }
    }

    private void publishPaymentRefundEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishPaymentRefund(
                    new PaymentRefundRequestedEvent(order.getId(), order.getClientId(), order.getTotalPrice()), sagaId, correlationId);
        } catch (Exception e) {
            log.error("CRITICAL: Failed to publish payment.refund event for orderId: {}", order.getId(), e);
        }
    }
}

package com.restaurant.order.service.impl;

import com.restaurant.order.client.MenuClient;
import com.restaurant.order.client.PaymentServiceClient;
import com.restaurant.order.dto.request.OrderItemRequest;
import com.restaurant.order.dto.request.PlaceOrderRequest;
import com.restaurant.order.dto.response.OrderResponse;
import com.restaurant.order.dto.snapshot.MealPriceSnapshot;
import com.restaurant.order.entity.Order;
import com.restaurant.order.entity.OrderItem;
import com.restaurant.order.enums.OrderStatus;
import com.restaurant.order.enums.PaymentMethod;
import com.restaurant.order.events.OrderCreatedEvent;
import com.restaurant.order.events.payments.PaymentRefundRequestedEvent;
import com.restaurant.order.events.points.PointRedemptionRollbackRequestedEvent;
import com.restaurant.order.events.points.PointRedemptionRequestedEvent;
import com.restaurant.order.events.points.RewardPointsEarnedEvent;
import com.restaurant.order.exception.MenuServiceException;
import com.restaurant.order.exception.OrderNotFoundException;
import com.restaurant.order.exception.PointsException;
import com.restaurant.order.mapper.OrderMapper;
import com.restaurant.order.messaging.MessagePublisher;
import com.restaurant.order.repository.OrderRepository;
import com.restaurant.order.service.OrderCalculator;
import com.restaurant.order.service.OrderService;
import jakarta.annotation.Nullable;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.transaction.interceptor.TransactionAspectSupport;
import org.springframework.web.server.ResponseStatusException;

import java.util.List;
import java.util.UUID;

@Service
@Slf4j
@RequiredArgsConstructor
public class OrderServiceImpl implements OrderService {

    private final OrderRepository orderRepository;
    private final MessagePublisher messagePublisher;
    private final OrderMapper orderMapper;
    private final OrderCalculator orderCalculator;
    private final MenuClient menuClient;
    private final PaymentServiceClient paymentServiceClient;

    @Transactional(rollbackFor = Exception.class)
    @Override
    public OrderResponse placeOrder(PlaceOrderRequest request, Long clientId) {
        log.info("Placing order for customerId: {}", clientId);

        // 1. Validate points
        int pointsToRedeem = request.points() != null ? request.points() : 0;
        int discount = switch (pointsToRedeem) {
            case 0 -> 0;
            case 100 -> 10;
            case 200 -> 20;
            case 300 -> 30;
            default -> throw new PointsException(
                    "Invalid redemption points. Allowed values are 100, 200, or 300." // cancel order process
            );
        };

        Order order = Order.builder()
                .clientId(clientId)
                .discount(discount)
                .paymentMethod(request.paymentMethod())
                .build();

        // 2. Fetch price snapshots from menu-service and build items
        for (OrderItemRequest itemReq : request.items()) {
            MealPriceSnapshot meal = menuClient.getMealById(itemReq.mealId());
            order.getItems().add(OrderItem.builder()
                    .order(order)
                    .mealId(meal.id())
                    .snapshotName(meal.name())
                    .snapshotPrice(meal.price())
                    .quantity(itemReq.quantity())
                    .build());
        }

        // 3. Calculate total price (with point discount if applicable)
        orderCalculator.calculateTotals(order);

        // 4. Reserve stock — if this fails, nothing is written to DB
        log.info("Reserving stock for order...");
        try {
            menuClient.reserveStock(request.items());
        } catch (Exception e) {
            log.error("Failed to reserve stock for order.", e);
            throw new MenuServiceException("Cannot reserve stock for order. The stock may be insufficient");
        }

        try {
            // 5. Persist to DB — status starts as PENDING
            Order savedOrder = orderRepository.save(order);
            log.info("Order saved with id: {} and status PENDING", savedOrder.getId());

            // 6. Trigger next step in saga
            if (pointsToRedeem != 0) {
                log.info("Triggering async point redemption for {} points...", pointsToRedeem);
                publishPointRedemptionRequestedEvent(savedOrder);
            } else {
                // Check payment method - only call payment service for non-cash payments
                if (!request.paymentMethod().equals(PaymentMethod.CASH)) {
                    savedOrder.setStatus(OrderStatus.AWAITING_PAYMENT);
                    createPaymentIntentSync(savedOrder);
                } else {
                    log.info("Payment method is CASH for order {}, skipping payment service call", savedOrder.getId());
                    publishOrderCreatedEvent(savedOrder);
                }
                orderRepository.save(savedOrder);
            }

            return orderMapper.toResponse(savedOrder);
        } catch (Exception e) {
            log.error("Failed to complete order placement for clientId: {}. Rolling back stock.", clientId, e);
            try {
                menuClient.rollbackStock(buildItemRequests(order));
            } catch (Exception rollbackEx) {
                log.error("CRITICAL: Failed to rollback stock after order placement failure for clientId: {}", clientId, rollbackEx);
            }
            throw e; // Re-throw the original exception (PointsException, PaymentException, or DB exception)
        }
    }

    @Transactional
    @Override
    public void confirmOrder(Long orderId, Long ticketId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.CONFIRMED) {
                            log.info("Order {} already confirmed, skipping.", orderId);
                            return;
                        }
                        order.setStatus(OrderStatus.CONFIRMED);
                        orderRepository.save(order);
                        log.info("Order {} status updated to CONFIRMED (ticket {})", orderId, ticketId);

                        // Reward points: 1 point per 5 EGP spent
                        if (order.getDiscount() == 0) {
                            int pointsToReward = order.getTotalPrice().intValue() / 5;
                            if (pointsToReward > 0) {
                                messagePublisher.publishRewardPointsEarned(
                                        new RewardPointsEarnedEvent(order.getClientId(), pointsToReward, order.getId())
                                );
                            }
                        }
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to confirm order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for confirmation, orderId: {}", orderId)
        );
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public void markPaymentSucceeded(Long orderId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.PAID) {
                            log.info("Order {} already marked as PAID, skipping.", orderId);
                            return;
                        }

                        if (order.getStatus() != OrderStatus.AWAITING_PAYMENT) {
                            log.warn("Order {} is in status {}, expected AWAITING_PAYMENT. Ignoring payment success.", orderId, order.getStatus());
                            return;
                        }

                        order.setStatus(OrderStatus.PAID);
                        orderRepository.save(order);
                        log.info("Payment succeeded for order {}. Notifying kitchen...", orderId);
                        publishOrderCreatedEvent(order);
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to process payment success for order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for payment success, ID: {}", orderId)
        );
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public void markPaymentFailed(Long orderId, String reason) {
        log.info("Payment failed for order {}, reason: {}. Cancelling order...", orderId, reason);
        cancelOrder(orderId, "Payment failed: " + reason);
    }


    @Transactional
    @Override
    public void markPointRedemptionSucceeded(Long orderId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.AWAITING_PAYMENT || order.getStatus() == OrderStatus.PAID) {
                            log.info("Order {} already processed point redemption, skipping.", orderId);
                            return;
                        }

                        if (order.getStatus() != OrderStatus.PENDING) {
                            log.warn("Order {} is in status {}, expected PENDING. Ignoring point redemption success.", orderId, order.getStatus());
                            return;
                        }

                        // Check payment method - only call payment service for non-cash payments
                        if (!order.getPaymentMethod().equals(PaymentMethod.CASH)) {
                            order.setStatus(OrderStatus.AWAITING_PAYMENT);
                            orderRepository.save(order);
                            log.info("Point redemption succeeded for order {}. Proceeding to payment...", orderId);
                            createPaymentIntentSync(order);
                        } else {
                            log.info("Payment method is CASH for order {}, skipping payment service call and publishing order created", orderId);
                            publishOrderCreatedEvent(order);
                        }
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to process point redemption success for order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for point redemption success, ID: {}", orderId)
        );
    }

    @Transactional
    @Override
    public void markPointRedemptionFailed(Long orderId, String reason) {
        log.info("Point redemption failed for order {}, reason: {}. Cancelling order...", orderId, reason);
        cancelOrder(orderId, "Point redemption failed: " + reason);
    }

    @Override
    public OrderResponse retrieveOrder(Long orderId) {
        Order order = orderRepository.findById(orderId)
                .orElseThrow(() -> new OrderNotFoundException(orderId));
        return orderMapper.toResponse(order);
    }

    @Transactional
    @Override
    public void cancelOrder(Long orderId, @Nullable String reason) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        OrderStatus status = order.getStatus();

                        // 0. Short-circuit if already canceled
                        if (status == OrderStatus.CANCELED) {
                            log.info("Order {} already cancelled, skipping.", orderId);
                            return;
                        }

                        // 1. Refuse Cancellation Check
                        boolean isAdvancedStage = (status == OrderStatus.PREPARING || status == OrderStatus.READY);
                        boolean isPaidOrConfirmed = (status == OrderStatus.PAID || status == OrderStatus.CONFIRMED);
                        boolean isNotCash = !PaymentMethod.CASH.equals(order.getPaymentMethod());

                        if (isAdvancedStage) {
                            log.warn("Cancellation refused for order {}. Status is {} ", orderId, status);
                            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Cannot cancel order that is already started preparing");
                        }

                        // 2. Rollback Stock
                        try {
                            log.info("Rolling back stock for cancelled order {}", orderId);
                            menuClient.rollbackStock(buildItemRequests(order));
                        } catch (Exception e) {
                            log.error("Failed to rollback stock for cancelled order {}", orderId, e);
                        }

                        // 3. Refund Payment if order was paid or confirmed (but passes cancellation check)
                        if (isPaidOrConfirmed && isNotCash) {
                            log.info("Triggering payment refund for order {}", orderId);
                            publishPaymentRefundEvent(order);
                        }

                        // 4. Rollback Points (Refund points if discount exists and order is NOT pending)
                        if (order.getDiscount() != 0 && status != OrderStatus.PENDING) {
                            log.info("Triggering point redemption rollback for order {}", orderId);
                            publishPointRedemptionRollbackEvent(order);
                        }

                        // 5. Finalize Cancellation State
                        order.setStatus(OrderStatus.CANCELED);
                        orderRepository.save(order);
                        log.info("Order {} cancelled. Reason: {}", orderId, reason != null ? reason : "Client Cancellation Request");

                    } catch (ResponseStatusException e) {
                        // Pass through client errors cleanly without marking transaction for forced system rollback
                        throw e;
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to cancel order {}. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> {
                    log.error("MANUAL INTERVENTION REQUIRED: Order not found for cancellation, orderId: {}", orderId);
                    throw new ResponseStatusException(HttpStatus.NOT_FOUND, "Order not found");
                }
        );
    }

    @Transactional
    @Override
    public void onTicketReady(Long orderId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.READY) {
                            log.info("Order {} already marked as READY, skipping.", orderId);
                            return;
                        }
                        order.setStatus(OrderStatus.READY);
                        orderRepository.save(order);
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to mark order {} as ready. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for ticket ready status, ID: {}", orderId)
        );
    }

    @Transactional
    @Override
    public void onTicketStarted(Long orderId, Long ticketId) {
        orderRepository.findById(orderId).ifPresentOrElse(
                order -> {
                    try {
                        if (order.getStatus() == OrderStatus.PREPARING) {
                            log.info("Order {} already marked as PREPARING, skipping.", orderId);
                            return;
                        }
                        order.setStatus(OrderStatus.PREPARING);
                        orderRepository.save(order);
                        log.info("Order {} status updated to PREPARING (ticket {})", orderId, ticketId);
                    } catch (Exception e) {
                        log.error("MANUAL INTERVENTION REQUIRED: Failed to mark order {} as preparing. Error: {}", orderId, e.getMessage());
                        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
                    }
                },
                () -> log.error("MANUAL INTERVENTION REQUIRED: Order not found for ticket started status, ID: {}", orderId)
        );
    }


    // --- Private helpers ---

    private List<OrderItemRequest> buildItemRequests(Order order) {
        return order.getItems().stream()
                .map(item -> new OrderItemRequest(item.getMealId(), item.getQuantity()))
                .toList();
    }

    private void publishOrderCreatedEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishOrderCreated(
                    new OrderCreatedEvent(order.getId()), sagaId, correlationId);
        } catch (Exception e) {
            log.error("Failed to publish order.created event for orderId: {}", order.getId(), e);
            throw new RuntimeException("Order created but failed to notify kitchen service", e);
        }
    }

    private void createPaymentIntentSync(Order order) {
        PaymentServiceClient.PaymentIntentResponse response = paymentServiceClient.createPaymentIntent(

                order.getId(), order.getClientId(), order.getTotalPrice(), "egp");

        order.setStripePaymentIntentId(response.paymentIntentId());
        order.setStripeClientSecret(response.clientSecret());
        orderRepository.save(order);
        log.info("PaymentIntent created and stored for order {}: intentId={}", order.getId(), response.paymentIntentId());
    }

    private void publishPointRedemptionRequestedEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishPointRedemptionRequested(
                    new PointRedemptionRequestedEvent(order.getId(), order.getClientId(), order.getDiscount() * 10), sagaId, correlationId);
        } catch (Exception e) {
            log.error("Failed to publish point-redemption.requested event for orderId: {}", order.getId(), e);
            throw new PointsException("Order placement failed due to point redemption request failure");
        }
    }

    private void publishPointRedemptionRollbackEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishPointRedemptionRollback(
                    new PointRedemptionRollbackRequestedEvent(order.getId(), order.getClientId(), order.getDiscount() * 10), sagaId, correlationId);
        } catch (Exception e) {
            log.error("CRITICAL: Failed to publish point-redemption.rollback event for orderId: {}", order.getId(), e);
        }
    }

    private void publishPaymentRefundEvent(Order order) {
        try {
            String sagaId = UUID.randomUUID().toString();
            String correlationId = UUID.randomUUID().toString();
            messagePublisher.publishPaymentRefund(
                    new PaymentRefundRequestedEvent(order.getId(), order.getClientId(), order.getTotalPrice()), sagaId, correlationId);
        } catch (Exception e) {
            log.error("CRITICAL: Failed to publish payment.refund event for orderId: {}", order.getId(), e);
        }
    }

    @Override
    public List<OrderResponse> getClientOrderHistory(Long clientId) {
        List<Order> orders = orderRepository.findByClientIdOrderByCreatedAtDesc(clientId);
        return orders.stream()
                .map(orderMapper::toResponse)
                .collect(Collectors.toList());
    }
}

package com.restaurant.kitchen.messaging;

import com.restaurant.kitchen.events.OrderCreatedEvent;
import com.restaurant.kitchen.events.chefProfileEvents.ProfileCreationFailedEvent;
import com.restaurant.kitchen.events.UserCreatedEvent;
import com.restaurant.kitchen.events.ticketEvents.TicketCreationFailedEvent;
import com.restaurant.kitchen.service.ChefService;
import com.restaurant.kitchen.service.TicketService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.messaging.handler.annotation.Header;
import org.springframework.stereotype.Component;


@Component
@RequiredArgsConstructor
@Slf4j
public class MessageListener {

    private final ChefService chefService;
    private final TicketService ticketService;

    private final MessagePublisher publisher;

    @RabbitListener(queues = "${app.rabbitmq.queues.user-created.name}")
    public void onUserCreated(UserCreatedEvent event,
                              @Header(value = "correlationId", required = false) String correlationId,
                              @Header(value = "sagaId", required = false) String sagaId) {

        if (sagaId == null || correlationId == null) {
            log.error("Missing required headers on user.created event, discarding message, event: {}", event);
            return;  // discard — No requeue
        }
        chefService.createChefProfile(event, correlationId, sagaId);
    }

    @RabbitListener(queues = "${app.rabbitmq.queues.user-created.dlq-name}")
    public void onUserCreatedFailure(UserCreatedEvent event,
                                     @Header("sagaId") String sagaId,
                                     @Header("correlationId") String correlationId) {

        log.error("Message moved to DLQ after max retries. Sending final failure event for user: {}", event.getId());

        try {

            ProfileCreationFailedEvent failedEvent = new ProfileCreationFailedEvent(
                    event.getId(),
                    "Chef profile creation failed due to technical error after multiple retries"
            );
            publisher.publishChefFailed(failedEvent, sagaId, correlationId);

        } catch (Exception e) {

            // handle failed event publish failure
            log.error("CRITICAL: DLQ Processing failed for Saga: {}. " +
                            "Manual intervention required! Event Data: {}",
                    sagaId, event, e);

            // By not throwing an exception here, we effectively ACK the message.
            // It leaves the queue (preventing a loop), but the data is safe in LOGS.
        }
    }

    @RabbitListener(queues = "${app.rabbitmq.queues.order-created.name}")
    public void onOrderCreated(OrderCreatedEvent event,
                               @Header(value = "correlationId", required = false) String correlationId,
                               @Header(value = "sagaId", required = false) String sagaId) {

        if (sagaId == null || correlationId == null) {
            log.error("Missing required headers on order.created event, discarding message, event: {}", event);
            return;  // discard — No requeue
        }
        ticketService.createKitchenTicket(event, correlationId, sagaId);
    }

    @RabbitListener(queues = "${app.rabbitmq.queues.order-created.dlq-name}")
    public void onOrderCreatedFailure(OrderCreatedEvent event,
                                     @Header("sagaId") String sagaId,
                                     @Header("correlationId") String correlationId) {

        log.error("Message moved to DLQ after max retries. Sending final failure event for order: {}", event.getId());

        try {

            TicketCreationFailedEvent failedEvent = new TicketCreationFailedEvent(
                    event.getId(),
                    "Kitchen ticket creation failed due to technical error after multiple retries"
            );
            publisher.publishTicketFailed(failedEvent, sagaId, correlationId);

        } catch (Exception e) {

            // handle failed event publish failure
            log.error("CRITICAL: DLQ Processing failed for Saga: {}. " +
                            "Manual intervention required! Event Data: {}",
                    sagaId, event, e);

            // By not throwing an exception here, we effectively ACK the message.
            // It leaves the queue (preventing a loop), but the data is safe in LOGS.
        }
    }
}

