        // Idempotency check
        if (existingTicket.isPresent()) {

            log.info("Ticket already exists, re-publishing creation event. orderId: {}", event.getId());

            publisher.publishTicketCreated(
                    new TicketCreatedEvent(event.getId(), existingTicket.get().getId()),
                    sagaId, correlationId);

            return; //spring Ack the message automatically since it did not throw an exception
        }

        try {
            KitchenTicket ticket = kitchenTicketRepository.save(
                    KitchenTicket.builder()  //manual fields setting is necessary therefore mapper is not used in this case
                            .orderId(event.getId())
                            .assignedChef(autoAssignChef())
                            .build()
            );
            publisher.publishTicketCreated(
                    new TicketCreatedEvent(event.getId(), ticket.getId()),
                    sagaId, correlationId);
        } catch (Exception exception) {
            log.error("Kitchen ticket creation failed", exception); // due to publish failure or save failure or unavailable chefs

            // rollback DB if save succeeded but publish failed → prevents duplicate on retry
            // and nack the message to re-queue or route to dlq if max-attempts have been reached
            // when goes to dlq then publish order-created failed event to tell the engaged services to roll back
            throw new RuntimeException("Kitchen ticket creation failed for orderId: " + event.getId());
        }
    }

    private ChefProfile autoAssignChef() {
        return chefProfileRepository
                .findMostAvailableActiveChefs(ChefStatus.ACTIVE, TicketStatus.QUEUED, PageRequest.of(0, 1))
                .stream()
                .findFirst()
                .orElseThrow(() -> new IllegalStateException("No available chefs to assign ticket")); // ticket cannot be created; therefore, nacking is necessary
    }

    @Transactional(rollbackFor = Exception.class) //both of updating db and publishing event must success
    @Override
    public KitchenTicketDTO updateTicketStatus(Long id, TicketStatus status) {

        KitchenTicket retrievedTicket = kitchenTicketRepository.findById(id)
                .orElseThrow(() -> new TicketNotFoundException(id));

        retrievedTicket.setStatus(status);

        if (status == TicketStatus.READY)
            publisher.publishTicketReady(
                    new TicketReadyEvent(retrievedTicket.getOrderId(), id),
                    UUID.randomUUID().toString());

        return ticketMapper.toDTO(retrievedTicket);
    }

    @Transactional(readOnly = true)
    @Override
    public List<KitchenTicketDTO> getActiveTickets() {

        List<KitchenTicket> activeTickets = kitchenTicketRepository.findByStatusNot(TicketStatus.READY);
        return ticketMapper.toDTOList(activeTickets);
    }

    @Transactional(rollbackFor = Exception.class)
    @Override
    public void startTicketPreparation(Long id, String correlationId) {

        KitchenTicket retrievedTicket = kitchenTicketRepository.findById(id)
                .orElseThrow(() -> new TicketNotFoundException(id));

        retrievedTicket.setStatus(TicketStatus.PREPARING);
        kitchenTicketRepository.save(retrievedTicket);

        publisher.publishTicketStarted(
                new TicketStartedEvent(retrievedTicket.getOrderId(), id),
                correlationId);
    }
}

package com.restaurant.kitchen.messaging;

import com.restaurant.kitchen.events.OrderCanceledEvent;
import com.restaurant.kitchen.events.OrderCreatedEvent;
import com.restaurant.kitchen.events.UserCreatedEvent;
import com.restaurant.kitchen.events.chefProfileEvents.ProfileCreationFailedEvent;
import com.restaurant.kitchen.events.ticketEvents.TicketCanceledFailedEvent;
import com.restaurant.kitchen.events.ticketEvents.TicketCreationFailedEvent;
import com.restaurant.kitchen.service.ChefService;
import com.restaurant.kitchen.service.TicketService;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class MessageListenerTest {

    @Mock
    private ChefService chefService;

    @Mock
    private TicketService ticketService;

    @Mock
    private MessagePublisher publisher;

    @InjectMocks
    private MessageListener messageListener;

    // ── onUserCreated ───────────────────────────────────────────────────────

    @Test
    void shouldCreateChefProfileOnUserCreated() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(100L);

        messageListener.onUserCreated(event, "corr-001", "saga-001");

        verify(chefService).createChefProfile(event, "corr-001", "saga-001");
    }

    // ── onUserCreatedFailure (DLQ) ─────────────────────────────────────────

    @Test
    void shouldPublishChefFailedEventOnUserCreatedDLQ() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(100L);

        messageListener.onUserCreatedFailure(event, "saga-001", "corr-001");

        verify(publisher).publishChefFailed(any(ProfileCreationFailedEvent.class), eq("saga-001"), eq("corr-001"));
    }

    // ── onOrderCreated ─────────────────────────────────────────────────────

    @Test
    void shouldCreateKitchenTicketOnOrderCreated() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        messageListener.onOrderCreated(event, "corr-001", "saga-001");

        verify(ticketService).createKitchenTicket(event, "corr-001", "saga-001");
    }

    // ── onOrderCreatedFailure (DLQ) ─────────────────────────────────────────

    @Test
    void shouldPublishTicketFailedEventOnOrderCreatedDLQ() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        messageListener.onOrderCreatedFailure(event, "saga-001", "corr-001");

        verify(publisher).publishTicketFailed(any(TicketCreationFailedEvent.class), eq("saga-001"), eq("corr-001"));
    }

    // ── onOrderCancelled ───────────────────────────────────────────────────

    @Test
    void shouldCancelKitchenTicketOnOrderCancelled() {
        OrderCanceledEvent event = new OrderCanceledEvent();
        event.setId(100L);

        messageListener.onOrderCancelled(event, "saga-001", "corr-001");

        verify(ticketService).cancelKitchenTicket(100L, "saga-001", "corr-001");
    }

    // ── onOrderCancelledFailure (DLQ) ─────────────────────────────────────

    @Test
    void shouldPublishTicketCanceledFailedEventOnOrderCancelledDLQ() {
        OrderCanceledEvent event = new OrderCanceledEvent();
        event.setId(100L);

        messageListener.onOrderCancelledFailure(event, "saga-001", "corr-001");

        verify(publisher).publishTicketCanceledFailed(any(TicketCanceledFailedEvent.class), eq("saga-001"), eq("corr-001"));
    }
}

