package com.restaurant.kitchen.service;

import com.restaurant.kitchen.dto.ChefProfileDTO;
import com.restaurant.kitchen.entity.ChefProfile;
import com.restaurant.kitchen.enums.ChefStatus;
import com.restaurant.kitchen.enums.Station;
import com.restaurant.kitchen.events.UserCreatedEvent;
import com.restaurant.kitchen.events.chefProfileEvents.ProfileCreatedEvent;
import com.restaurant.kitchen.exception.ChefNotFoundException;
import com.restaurant.kitchen.mapper.ChefProfileMapper;
import com.restaurant.kitchen.messaging.MessagePublisher;
import com.restaurant.kitchen.repository.ChefProfileRepository;
import com.restaurant.kitchen.service.impl.ChefServiceImpl;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.*;

class ChefServiceTest {

    @Mock
    private ChefProfileRepository chefProfileRepository;

    @Mock
    private ChefProfileMapper chefProfileMapper;

    @Mock
    private MessagePublisher publisher;

    @InjectMocks
    private ChefServiceImpl chefService;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
    }

    @Test
    void createChefProfileSuccessfullyWhenUserIsChefAndProfileDoesNotExist() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(1L);
        event.setRole("CHEF");

        when(chefProfileRepository.findByAuthUserId(1L)).thenReturn(Optional.empty());

        chefService.createChefProfile(event, "corr123", "saga123");

        verify(chefProfileRepository, times(1)).save(any(ChefProfile.class));
        verify(publisher, times(1)).publishChefCreated(any(ProfileCreatedEvent.class), eq("saga123"), eq("corr123"));
    }

    @Test
    void ignoreChefProfileCreationWhenUserIsNotChef() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(1L);
        event.setRole("CUSTOMER");

        chefService.createChefProfile(event, "corr123", "saga123");

        verify(chefProfileRepository, never()).findByAuthUserId(anyLong());
        verify(chefProfileRepository, never()).save(any());
        verify(publisher, never()).publishChefCreated(any(), any(), any());
    }

    @Test
    void republishCreationEventWhenChefProfileAlreadyExists() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(1L);
        event.setRole("CHEF");

        ChefProfile existingChef = new ChefProfile();
        existingChef.setId(10L);
        existingChef.setAuthUserId(1L);

        when(chefProfileRepository.findByAuthUserId(1L)).thenReturn(Optional.of(existingChef));

        chefService.createChefProfile(event, "corr123", "saga123");

        verify(chefProfileRepository, never()).save(any());
        verify(publisher, times(1)).publishChefCreated(any(ProfileCreatedEvent.class), eq("saga123"), eq("corr123"));
    }

    @Test
    void throwRuntimeExceptionWhenChefProfileCreationFailsOnDatabaseSave() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(1L);
        event.setRole("CHEF");

        when(chefProfileRepository.findByAuthUserId(1L)).thenReturn(Optional.empty());
        when(chefProfileRepository.save(any())).thenThrow(new RuntimeException("DB error"));

        assertThrows(RuntimeException.class, () -> 
            chefService.createChefProfile(event, "corr123", "saga123")
        );

        verify(publisher, never()).publishChefCreated(any(), any(), any());
    }

    @Test
    void throwRuntimeExceptionWhenChefProfileCreationFailsOnPublishingEvent() {
        UserCreatedEvent event = new UserCreatedEvent();
        event.setId(1L);
        event.setRole("CHEF");

        when(chefProfileRepository.findByAuthUserId(1L)).thenReturn(Optional.empty());
        doThrow(new RuntimeException("Publish error"))
                .when(publisher).publishChefCreated(any(), any(), any());

        assertThrows(RuntimeException.class, () -> 
            chefService.createChefProfile(event, "corr123", "saga123")
        );

        verify(chefProfileRepository, times(1)).save(any());
    }

    @Test
    void updateChefDisplayNameSuccessfullyWhenChefExists() {
        Long chefId = 1L;
        String newDisplayName = "New Display Name";
        ChefProfile chef = new ChefProfile();
        chef.setId(chefId);
        chef.setDisplayName("Old Display Name");
        ChefProfileDTO dto = new ChefProfileDTO(chefId, 1L, "New Display Name", Station.UNASSIGNED, ChefStatus.ACTIVE);

        when(chefProfileRepository.findById(chefId)).thenReturn(Optional.of(chef));
        when(chefProfileMapper.toDTO(chef)).thenReturn(dto);

        ChefProfileDTO result = chefService.updateChefDisplayName(chefId, newDisplayName);

        assertEquals(newDisplayName, result.displayName());
        verify(chefProfileRepository, times(1)).findById(chefId);
    }

    @Test
    void throwChefNotFoundExceptionWhenUpdatingDisplayNameForNonExistentChef() {
        Long chefId = 1L;
        when(chefProfileRepository.findById(chefId)).thenReturn(Optional.empty());

        assertThrows(ChefNotFoundException.class, () -> 
            chefService.updateChefDisplayName(chefId, "Some Name")
        );

        verify(chefProfileRepository, times(1)).findById(chefId);
        verifyNoInteractions(chefProfileMapper);
    }

    @Test
    void updateChefStationSuccessfullyWhenChefExists() {
        Long chefId = 1L;
        Station newStation = Station.PASTRY;
        ChefProfile chef = new ChefProfile();
        chef.setId(chefId);
        chef.setStation(Station.GRILL);
        ChefProfileDTO dto = new ChefProfileDTO(chefId, 1L, "Chef John", Station.PASTRY, ChefStatus.ACTIVE);

        when(chefProfileRepository.findById(chefId)).thenReturn(Optional.of(chef));
        when(chefProfileMapper.toDTO(chef)).thenReturn(dto);

        ChefProfileDTO result = chefService.updateChefStation(chefId, newStation);

        assertEquals(newStation, result.station());
        verify(chefProfileRepository, times(1)).findById(chefId);
    }

    @Test
    void throwChefNotFoundExceptionWhenUpdatingStationForNonExistentChef() {
        Long chefId = 1L;
        when(chefProfileRepository.findById(chefId)).thenReturn(Optional.empty());

        assertThrows(ChefNotFoundException.class, () -> 
            chefService.updateChefStation(chefId, Station.PASTRY)
        );

        verify(chefProfileRepository, times(1)).findById(chefId);
        verifyNoInteractions(chefProfileMapper);
    }

    @Test
    void updateChefStatusSuccessfullyWhenChefExists() {
        Long chefId = 1L;
        ChefStatus newStatus = ChefStatus.ACTIVE;
        ChefProfile chef = new ChefProfile();
        chef.setId(chefId);
        chef.setStatus(ChefStatus.INACTIVE);
        ChefProfileDTO dto = new ChefProfileDTO(chefId, 1L, "Chef John", Station.UNASSIGNED, ChefStatus.ACTIVE);

        when(chefProfileRepository.findById(chefId)).thenReturn(Optional.of(chef));
        when(chefProfileMapper.toDTO(chef)).thenReturn(dto);

        ChefProfileDTO result = chefService.updateChefStatus(chefId, newStatus);

        assertEquals(newStatus, result.status());
        verify(chefProfileRepository, times(1)).findById(chefId);
    }

    @Test
    void throwChefNotFoundExceptionWhenUpdatingStatusForNonExistentChef() {
        Long chefId = 1L;
        when(chefProfileRepository.findById(chefId)).thenReturn(Optional.empty());

        assertThrows(ChefNotFoundException.class, () -> 
            chefService.updateChefStatus(chefId, ChefStatus.ACTIVE)
        );

        verify(chefProfileRepository, times(1)).findById(chefId);
        verifyNoInteractions(chefProfileMapper);
    }
}

package com.restaurant.kitchen.service;

import com.restaurant.kitchen.dto.KitchenTicketDTO;
import com.restaurant.kitchen.entity.ChefProfile;
import com.restaurant.kitchen.entity.KitchenTicket;
import com.restaurant.kitchen.enums.ChefStatus;
import com.restaurant.kitchen.enums.TicketStatus;
import com.restaurant.kitchen.events.OrderCreatedEvent;
import com.restaurant.kitchen.events.ticketEvents.TicketReadyEvent;
import com.restaurant.kitchen.exception.TicketNotFoundException;
import com.restaurant.kitchen.mapper.KitchenTicketMapper;
import com.restaurant.kitchen.messaging.MessagePublisher;
import com.restaurant.kitchen.repository.ChefProfileRepository;
import com.restaurant.kitchen.repository.KitchenTicketRepository;
import com.restaurant.kitchen.service.impl.TicketServiceImpl;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.data.domain.PageRequest;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class TicketServiceImplTest {

    @Mock
    private KitchenTicketRepository kitchenTicketRepository;

    @Mock
    private ChefProfileRepository chefProfileRepository;

    @Mock
    private KitchenTicketMapper ticketMapper;

    @Mock
    private MessagePublisher publisher;

    @InjectMocks
    private TicketServiceImpl ticketService;

    // ── createKitchenTicket ──────────────────────────────────────────────

    @Test
    void shouldRepublishTicketCreatedWhenTicketAlreadyExists() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        KitchenTicket existingTicket = buildTicket(TicketStatus.PREPARING);
        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.of(existingTicket));

        ticketService.createKitchenTicket(event, "corr-001", "saga-001");

        verify(kitchenTicketRepository, never()).save(any());
        verify(publisher).publishTicketCreated(any(), eq("saga-001"), eq("corr-001"));
    }

    @Test
    void shouldSaveAndPublishWhenTicketDoesNotExistAndChefAvailable() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        ChefProfile availableChef = new ChefProfile();
        availableChef.setId(10L);

        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.empty());
        when(chefProfileRepository.findMostAvailableActiveChefs(ChefStatus.ACTIVE, TicketStatus.PREPARING, PageRequest.of(0, 1)))
                .thenReturn(List.of(availableChef));

        KitchenTicket savedTicket = buildTicket(TicketStatus.PREPARING);
        savedTicket.setId(1L);
        when(kitchenTicketRepository.save(any(KitchenTicket.class))).thenReturn(savedTicket);

        ticketService.createKitchenTicket(event, "corr-001", "saga-001");

        verify(kitchenTicketRepository).save(any(KitchenTicket.class));
        verify(publisher).publishTicketCreated(any(), eq("saga-001"), eq("corr-001"));
    }

    @Test
    void shouldThrowWhenNoChefAvailable() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.empty());
        when(chefProfileRepository.findMostAvailableActiveChefs(ChefStatus.ACTIVE, TicketStatus.PREPARING, PageRequest.of(0, 1)))
                .thenReturn(List.of());

        assertThrows(RuntimeException.class, () -> ticketService.createKitchenTicket(event, "corr-001", "saga-001"));

        verify(kitchenTicketRepository, never()).save(any());
        verifyNoInteractions(publisher);
    }

    // ── updateTicketStatus ───────────────────────────────────────────────

    @Test
    void shouldUpdateTicketStatusSuccessfully() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.DONE, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        KitchenTicketDTO result = ticketService.updateTicketStatus(1L, TicketStatus.DONE);

        assertEquals(TicketStatus.DONE, ticket.getStatus());
        assertEquals(TicketStatus.DONE, result.status());
        verify(kitchenTicketRepository, never()).save(any()); // uses dirty checking
    }

    @Test
    void shouldPublishTicketReadyEventWhenStatusIsReady() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.READY, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        ticketService.updateTicketStatus(1L, TicketStatus.READY);

        verify(publisher).publishTicketReady(any(TicketReadyEvent.class), anyString());
    }

    @Test
    void shouldNotPublishEventWhenStatusIsNotReady() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.DONE, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        ticketService.updateTicketStatus(1L, TicketStatus.DONE);

        verifyNoInteractions(publisher);
    }

    @Test
    void shouldThrowTicketNotFoundWhenUpdatingStatusOfNonExistentTicket() {
        when(kitchenTicketRepository.findById(99L)).thenReturn(Optional.empty());

        assertThrows(TicketNotFoundException.class,
                () -> ticketService.updateTicketStatus(99L, TicketStatus.READY));

        verify(kitchenTicketRepository, never()).save(any());
        verifyNoInteractions(publisher);
    }

    // ── getActiveTickets ─────────────────────────────────────────────────

    @Test
    void shouldReturnActiveTicketsSuccessfully() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.PREPARING, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findByStatusNot(TicketStatus.DONE)).thenReturn(List.of(ticket));
        when(ticketMapper.toDTOList(List.of(ticket))).thenReturn(List.of(dto));

        List<KitchenTicketDTO> result = ticketService.getActiveTickets();

        assertEquals(1, result.size());
        assertEquals(TicketStatus.PREPARING, result.get(0).status());
    }

    @Test
    void shouldReturnEmptyListWhenNoActiveTicketsExist() {
        when(kitchenTicketRepository.findByStatusNot(TicketStatus.DONE)).thenReturn(List.of());
        when(ticketMapper.toDTOList(List.of())).thenReturn(List.of());

        List<KitchenTicketDTO> result = ticketService.getActiveTickets();

        assertEquals(0, result.size());
    }

    // ── helper ───────────────────────────────────────────────────────────

    private KitchenTicket buildTicket(TicketStatus status) {
        ChefProfile chef = new ChefProfile();
        chef.setId(10L);
        chef.setDisplayName("Chef John");

        return KitchenTicket.builder()
                .id(1L)
                .orderId(100L)
                .status(status)
                .assignedChef(chef)
                .createdAt(LocalDateTime.now())
                .build();
    }
}

package com.restaurant.kitchen.service;

import com.restaurant.kitchen.dto.KitchenTicketDTO;
import com.restaurant.kitchen.entity.ChefProfile;
import com.restaurant.kitchen.entity.KitchenTicket;
import com.restaurant.kitchen.enums.ChefStatus;
import com.restaurant.kitchen.enums.TicketStatus;
import com.restaurant.kitchen.events.OrderCreatedEvent;
import com.restaurant.kitchen.events.ticketEvents.TicketReadyEvent;
import com.restaurant.kitchen.events.ticketEvents.TicketStartedEvent;
import com.restaurant.kitchen.exception.TicketNotFoundException;
import com.restaurant.kitchen.mapper.KitchenTicketMapper;
import com.restaurant.kitchen.messaging.MessagePublisher;
import com.restaurant.kitchen.repository.ChefProfileRepository;
import com.restaurant.kitchen.repository.KitchenTicketRepository;
import com.restaurant.kitchen.service.impl.TicketServiceImpl;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.data.domain.PageRequest;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class TicketServiceImplTest {

    @Mock
    private KitchenTicketRepository kitchenTicketRepository;

    @Mock
    private ChefProfileRepository chefProfileRepository;

    @Mock
    private KitchenTicketMapper ticketMapper;

    @Mock
    private MessagePublisher publisher;

    @InjectMocks
    private TicketServiceImpl ticketService;

    // ── createKitchenTicket ──────────────────────────────────────────────

    @Test
    void shouldRepublishTicketCreatedWhenTicketAlreadyExists() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        KitchenTicket existingTicket = buildTicket(TicketStatus.PREPARING);
        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.of(existingTicket));

        ticketService.createKitchenTicket(event, "corr-001", "saga-001");

        verify(kitchenTicketRepository, never()).save(any());
        verify(publisher).publishTicketCreated(any(), eq("saga-001"), eq("corr-001"));
    }

    @Test
    void shouldSaveAndPublishWhenTicketDoesNotExistAndChefAvailable() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        ChefProfile availableChef = new ChefProfile();
        availableChef.setId(10L);

        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.empty());
        when(chefProfileRepository.findMostAvailableActiveChefs(ChefStatus.ACTIVE, List.of(TicketStatus.PREPARING), PageRequest.of(0, 1)))
                .thenReturn(List.of(availableChef));

        KitchenTicket savedTicket = buildTicket(TicketStatus.PREPARING);
        savedTicket.setId(1L);
        when(kitchenTicketRepository.save(any(KitchenTicket.class))).thenReturn(savedTicket);

        ticketService.createKitchenTicket(event, "corr-001", "saga-001");

        verify(kitchenTicketRepository).save(any(KitchenTicket.class));
        verify(publisher).publishTicketCreated(any(), eq("saga-001"), eq("corr-001"));
    }

    @Test
    void shouldThrowWhenNoChefAvailable() {
        OrderCreatedEvent event = new OrderCreatedEvent();
        event.setId(100L);

        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.empty());
        when(chefProfileRepository.findMostAvailableActiveChefs(ChefStatus.ACTIVE, List.of(TicketStatus.PREPARING), PageRequest.of(0, 1)))
                .thenReturn(List.of());

        assertThrows(RuntimeException.class, () -> ticketService.createKitchenTicket(event, "corr-001", "saga-001"));

        verify(kitchenTicketRepository, never()).save(any());
        verifyNoInteractions(publisher);
    }

    // ── updateTicketStatus ───────────────────────────────────────────────

    @Test
    void shouldUpdateTicketStatusSuccessfully() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.READY, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        KitchenTicketDTO result = ticketService.updateTicketStatus(1L, TicketStatus.READY);

        assertEquals(TicketStatus.READY, ticket.getStatus());
        assertEquals(TicketStatus.READY, result.status());
        verify(kitchenTicketRepository, never()).save(any()); // uses dirty checking
    }

    @Test
    void shouldPublishTicketReadyEventWhenStatusIsReady() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.READY, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        ticketService.updateTicketStatus(1L, TicketStatus.READY);

        verify(publisher).publishTicketReady(any(TicketReadyEvent.class), anyString());
    }

    @Test
    void shouldNotPublishEventWhenStatusIsNotReady() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.CANCELED, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        ticketService.updateTicketStatus(1L, TicketStatus.CANCELED);

        verifyNoInteractions(publisher);
    }

    @Test
    void shouldThrowTicketNotFoundWhenUpdatingStatusOfNonExistentTicket() {
        when(kitchenTicketRepository.findById(99L)).thenReturn(Optional.empty());

        assertThrows(TicketNotFoundException.class,
                () -> ticketService.updateTicketStatus(99L, TicketStatus.READY));

        verify(kitchenTicketRepository, never()).save(any());
        verifyNoInteractions(publisher);
    }

    @Test
    void shouldPublishTicketStartedEventWhenStatusIsPreparing() {
        KitchenTicket ticket = buildTicket(TicketStatus.QUEUED);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.PREPARING, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        ticketService.updateTicketStatus(1L, TicketStatus.PREPARING);

        verify(publisher).publishTicketStarted(any(TicketStartedEvent.class), anyString());
    }

    @Test
    void shouldNotPublishEventWhenStatusUnchanged() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.PREPARING, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findById(1L)).thenReturn(Optional.of(ticket));
        when(ticketMapper.toDTO(ticket)).thenReturn(dto);

        KitchenTicketDTO result = ticketService.updateTicketStatus(1L, TicketStatus.PREPARING);

        assertEquals(TicketStatus.PREPARING, ticket.getStatus());
        verifyNoInteractions(publisher);
    }

    // ── cancelKitchenTicket ────────────────────────────────────────────────

    @Test
    void shouldCancelTicketSuccessfullyWhenQueued() {
        KitchenTicket ticket = buildTicket(TicketStatus.QUEUED);
        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.of(ticket));

        ticketService.cancelKitchenTicket(100L, "saga-001", "corr-001");

        assertEquals(TicketStatus.CANCELED, ticket.getStatus());
        verify(kitchenTicketRepository).save(ticket);
        verify(publisher).publishTicketCanceled(any(), eq("corr-001"));
    }

    @Test
    void shouldNotCancelTicketWhenAlreadyCanceled() {
        KitchenTicket ticket = buildTicket(TicketStatus.CANCELED);
        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.of(ticket));

        ticketService.cancelKitchenTicket(100L, "saga-001", "corr-001");

        assertEquals(TicketStatus.CANCELED, ticket.getStatus());
        verify(kitchenTicketRepository, never()).save(any());
        verify(publisher, never()).publishTicketCanceled(any(), anyString());
    }

    @Test
    void shouldThrowWhenCancelingNonQueuedTicket() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        when(kitchenTicketRepository.findByOrderId(100L)).thenReturn(Optional.of(ticket));

        assertThrows(IllegalStateException.class,
                () -> ticketService.cancelKitchenTicket(100L, "saga-001", "corr-001"));

        verify(kitchenTicketRepository, never()).save(any());
        verify(publisher, never()).publishTicketCanceled(any(), anyString());
    }

    @Test
    void shouldThrowWhenTicketNotFoundForCancellation() {
        when(kitchenTicketRepository.findByOrderId(99L)).thenReturn(Optional.empty());

        assertThrows(IllegalStateException.class,
                () -> ticketService.cancelKitchenTicket(99L, "saga-001", "corr-001"));

        verify(kitchenTicketRepository, never()).save(any());
        verify(publisher, never()).publishTicketCanceled(any(), anyString());
    }

    // ── getActiveTickets ─────────────────────────────────────────────────

    @Test
    void shouldReturnActiveTicketsSuccessfully() {
        KitchenTicket ticket = buildTicket(TicketStatus.PREPARING);
        KitchenTicketDTO dto = new KitchenTicketDTO(1L, 100L, TicketStatus.PREPARING, 10L, LocalDateTime.now());

        when(kitchenTicketRepository.findByStatusIn(List.of(TicketStatus.QUEUED, TicketStatus.PREPARING))).thenReturn(List.of(ticket));
        when(ticketMapper.toDTOList(List.of(ticket))).thenReturn(List.of(dto));

        List<KitchenTicketDTO> result = ticketService.getActiveTickets();

        assertEquals(1, result.size());
        assertEquals(TicketStatus.PREPARING, result.get(0).status());
    }

    @Test
    void shouldReturnEmptyListWhenNoActiveTicketsExist() {
        when(kitchenTicketRepository.findByStatusIn(List.of(TicketStatus.QUEUED, TicketStatus.PREPARING))).thenReturn(List.of());
        when(ticketMapper.toDTOList(List.of())).thenReturn(List.of());

        List<KitchenTicketDTO> result = ticketService.getActiveTickets();

        assertEquals(0, result.size());
    }

    // ── helper ───────────────────────────────────────────────────────────

    private KitchenTicket buildTicket(TicketStatus status) {
        ChefProfile chef = new ChefProfile();
        chef.setId(10L);
        chef.setDisplayName("Chef John");

        return KitchenTicket.builder()
                .id(1L)
                .orderId(100L)
                .status(status)
                .assignedChef(chef)
                .createdAt(LocalDateTime.now())
                .build();
    }
}
